1	// ===== KINETIC GRID CLOCK — Humans Since 1982 style =====
2	// 84 mini-clocks: 6 rows × 14 cols
3	// Each clock: 2 equal hands pivoting from centre (half-diameter each).
4	//   Overlap (same angle)  → single half-line
5	//   180° apart            → full diameter line  ─ or │
6	//   90° apart             → corner shape         ┌ ┐ └ ┘
7	// Cycle: 2 s ease-out → 21 s patterns → 2 s ease-in → 5 s display (HH:MM or MM:SS) → repeat
8	(function () {
9	  'use strict';
10	
11	  // ── Default config (override via /clock-controls.html + localStorage) ──────
12	  const DEFAULTS = {
13	    mode:          'clock',     // 'clock' | 'countdown'
14	    hours:         0,           // UTC offset for clock mode (e.g. +1 = UTC+1)
15	    countdownTime: '00:30',     // initial countdown time MM:SS
16	  };
17	
18	  // DEBUG: set to [d0,d1,d2,d3] to freeze display on specific digits; null = live
19	  const DEBUG_DIGITS = null;
20	
21	  // ── Config: read from localStorage, fall back to DEFAULTS ─────────────────
22	  function loadConfig() {
23	    const ls = k => localStorage.getItem(k);
24	    return {
25	      mode:         ls('clk_mode')           || DEFAULTS.mode,
26	      hours:        +(ls('clk_hours')        ?? DEFAULTS.hours),
27	      countdownTime:ls('clk_countdown_time') || DEFAULTS.countdownTime,
28	      countdownEnd: +(ls('clk_countdown_end')|| 0),
29	    };
30	  }
31	
32	  let cfg = loadConfig();
33	
34	  // Auto-start countdown on first load if no end time is stored
35	  if (cfg.mode === 'countdown' && !cfg.countdownEnd) {
36	    const [mm, ss] = DEFAULTS.countdownTime.split(':').map(Number);
37	    cfg.countdownEnd = Date.now() + (mm * 60 + ss) * 1000;
38	    localStorage.setItem('clk_countdown_end', cfg.countdownEnd);
39	  }
40	
41	  window.addEventListener('storage', () => { cfg = loadConfig(); });
42	
43	  // ── Timing ────────────────────────────────────────────────────────────────
44	  const ROWS = 6, COLS = 14, N = 84;
45	  const CYCLE = 30000, TIME_SHOW = 5000, TRANS_DUR = 2000;
46	  const PATTERN_END = CYCLE - TIME_SHOW;       // 25 000 ms
47	  const TRANS_START = PATTERN_END - TRANS_DUR; // 23 000 ms
48	
49	  // ── Hand-angle pairs [h1°, h2°]  (0=up 90=right 180=down 270=left) ──
50	  // Clock-face key: H:M → [H×30°, M×6°]
51	  // e.g. 6:15=[180,90]=TL  9:30=[270,180]=TR  12:15=[0,90]=BL  12:45=[0,270]=BR
52	  const H   = [90, 270];  // 3:45  — horizontal ─
53	  const V   = [0, 180];   // 12:30 — vertical   │
54	  const TL  = [90, 180];  // 6:15 / 3:30  — top-left corner     ┌
55	  const TR  = [270, 180]; // 9:30 / 6:45  — top-right corner    ┐
56	  const BL  = [90, 0];    // 12:15 / 3:00 — bottom-left corner  └
57	  const BR  = [270, 0];   // 12:45 / 9:00 — bottom-right corner ┘
58	  const I_D = [180, 180]; // 6:30  — interior top    (both down)
59	  const I_U = [0, 0];     // 12:00 — interior bottom (both up)
60	  const OFF = [45, 45];   // neutral — used in colon blank rows
61	  const NE  = [45, 45];   // 1:7.5   — diagonal top-right  ╱
62	  const NW  = [315, 315]; // 10:52.5 — diagonal top-left   ╲
63	  const SE  = [135, 135]; // 4:22.5  — diagonal bot-right  ╲
64	  const SW  = [225, 225]; // 7:37.5  — diagonal bot-left   ╱
65	
66	  // ── Digit angle tables — 18 hand-pairs each, 6 rows × 3 cols, row-major ──
67	  // Columns A–C, rows 0–5 top to bottom.
68	  // Digit 5 = digit 2 mirrored horizontally. Digit 6 = digit 9 mirrored vertically + horizontally.
69	  const DIGIT_ANGLES = [
70	    // 0 — full rectangle
71	    [ TL,H,TR,  V,I_D,V,  V,V,V,  V,V,V,  V,I_U,V,  BL,H,BR ],
72	    // 1 — serif top; SW fills empty left cells
73	    [ TL,H,TR,  BL,TR,V,  SW,V,V,  SW,V,V,  SW,V,V,  SW,BL,BR ],
74	    // 2
75	    [ TL,H,TR,  BL,TR,V,  TL,BR,V,  V,TL,BR,  V,BL,TR,  BL,H,BR ],
76	    // 3
77	    [ TL,H,TR,  BL,TR,V,  TL,BR,V,  BL,TR,V,  TL,BR,V,  BL,H,BR ],
78	    // 4
79	    [ TL,TR,TR,  V,V,V,  V,I_U,V,  BL,TR,V,  SW,V,V,  SW,BL,BR ],
80	    // 5 — 2 mirrored horizontally
81	    [ TL,H,TR,  V,TL,BR,  V,BL,TR,  BL,TR,V,  TL,BR,V,  BL,H,BR ],
82	    // 6 — 9 mirrored vertically + horizontally
83	    [ TL,H,TR,  V,TL,BR,  V,BL,TR,  V,I_D,V,  V,I_U,V,  BL,H,BR ],
84	    // 7 — diagonal descender (SE on right col rows 3–5)
85	    [ TL,H,TR,  BL,NE,V,  NW,NE,SW,  NE,NE,SE,  V,V,SE,  BL,BR,SE ],
86	    // 8
87	    [ TL,H,TR,  V,I_D,V,  SE,I_U,SW,  NE,I_D,NW,  V,I_U,V,  BL,H,BR ],
88	    // 9
89	    [ TL,H,TR,  V,I_D,V,  V,I_U,V,  BL,TR,V,  TL,BR,V,  BL,H,BR ],
90	  ];
91	
92	  // Colon sub-grid: 6 rows × 2 cols — two 2×2 square dots at rows 1–2 and 3–4
93	  const COLON = [
94	    [OFF, OFF], // row 0 — blank
95	    [TL,  TR],  // row 1 — top of upper dot
96	    [BL,  BR],  // row 2 — bottom of upper dot
97	    [TL,  TR],  // row 3 — top of lower dot
98	    [BL,  BR],  // row 4 — bottom of lower dot
99	    [OFF, OFF], // row 5 — blank
100	  ];
101	
102	  // ── DOM: reference pre-rendered 84 mini-clock cells ──────────────────────
103	  const allHands = document.querySelectorAll('#grid .hand');
104	  const hands = [];
105	  for (let i = 0; i < N; i++) {
106	    hands.push({ h1: allHands[i * 2], h2: allHands[i * 2 + 1] });
107	  }
108	
109	  // ── Helpers ───────────────────────────────────────────────────────────────
110	  const norm = a => ((a % 360) + 360) % 360;
111	  const ease = x => x < 0.5 ? 2*x*x : 1 - (-2*x + 2)**2 / 2;
112	
113	  function lerpA(from, to, p) {
114	    const d = norm(to - from);
115	    return from + (d > 180 ? d - 360 : d) * p;
116	  }
117	
118	  // Cache of last-written angles (flat: even = h1, odd = h2).
119	  // Skipping DOM writes for unchanged values avoids unnecessary style
120	  // invalidations and reduces GC pressure from template literal allocation.
121	  const _lastAngles = new Float64Array(N * 2).fill(NaN);
122	
123	  function apply(angles) {
124	    for (let i = 0; i < N; i++) {
125	      // Round to 2 dp — sub-hundredth-degree precision is invisible but
126	      // generates unique strings each frame, increasing GC load.
127	      const a1 = Math.round(angles[i][0] * 100) / 100;
128	      const a2 = Math.round(angles[i][1] * 100) / 100;
129	      const j  = i * 2;
130	      if (a1 !== _lastAngles[j]) {
131	        _lastAngles[j] = a1;
132	        hands[i].h1.style.transform = `rotate(${a1}deg)`;
133	      }
134	      if (a2 !== _lastAngles[j + 1]) {
135	        _lastAngles[j + 1] = a2;
136	        hands[i].h2.style.transform = `rotate(${a2}deg)`;
137	      }
138	    }
139	  }
140	
141	  // Pre-allocated output buffer for timeAngles()
142	  const _bufTime = Array.from({length: N}, () => [0, 0]);
143	
144	  // ── Time / Countdown display ───────────────────────────────────────────────
145	  function timeAngles() {
146	    let d0, d1, d2, d3, isZero = false;
147	
148	    if (DEBUG_DIGITS) {
149	      [d0, d1, d2, d3] = DEBUG_DIGITS;
150	
151	    } else if (cfg.mode === 'countdown') {
152	      const remaining = Math.max(0, cfg.countdownEnd - Date.now());
153	      isZero = cfg.countdownEnd > 0 && remaining === 0;
154	      const totalSec = Math.ceil(remaining / 1000);
155	      const mins = Math.min(99, Math.floor(totalSec / 60));
156	      const secs = totalSec % 60;
157	      d0 = Math.floor(mins / 10); d1 = mins % 10;
158	      d2 = Math.floor(secs / 10); d3 = secs % 10;
159	
160	    } else {
161	      const d   = new Date();
162	      const utcH = d.getUTCHours() + cfg.hours;
163	      const hh  = (((utcH % 24) + 24) % 24).toString().padStart(2, '0');
164	      const mm  = d.getUTCMinutes().toString().padStart(2, '0');
165	      d0 = +hh[0]; d1 = +hh[1]; d2 = +mm[0]; d3 = +mm[1];
166	    }
167	
168	    document.body.classList.toggle('countdown-zero', isZero);
169	
170	    const d0a = DIGIT_ANGLES[d0], d1a = DIGIT_ANGLES[d1];
171	    const d2a = DIGIT_ANGLES[d2], d3a = DIGIT_ANGLES[d3];
172	    // Column layout: [0-2]=d0 [3-5]=d1 [6-7]=colon [8-10]=d2 [11-13]=d3
173	    let i = 0;
174	    for (let r = 0; r < ROWS; r++) {
175	      for (let c = 0; c < COLS; c++) {
176	        let pair;
177	        if      (c <= 2)  pair = d0a[r * 3 + c];
178	        else if (c <= 5)  pair = d1a[r * 3 + c - 3];
179	        else if (c <= 7)  pair = COLON[r][c - 6];
180	        else if (c <= 10) pair = d2a[r * 3 + c - 8];
181	        else              pair = d3a[r * 3 + c - 11];
182	        _bufTime[i][0] = pair[0]; _bufTime[i][1] = pair[1]; i++;
183	      }
184	    }
185	    return _bufTime;
186	  }
187	
188	  // Pre-allocated reusable angle buffers — avoids creating 84+ new [h1,h2]
189	  // sub-arrays every frame (252+ allocations/frame during blend windows).
190	  // Each buffer is an Array of N 2-element arrays, mutated in place.
191	  const _bufOut    = Array.from({length: N}, () => [0, 0]);
192	  const _bufFrom   = Array.from({length: N}, () => [0, 0]);
193	  const _bufTo     = Array.from({length: N}, () => [0, 0]);
194	  const _bufInterp = Array.from({length: N}, () => [0, 0]); // ease-in/out phase
195	
196	  // Inlined version of clockAngles — writes directly into buf[i] to avoid
197	  // creating a temporary [a, b] array for each of the 84 cells per call.
198	  function patternAngles(t, pidx, buf) {
199	    let i = 0;
200	    for (let r = 0; r < ROWS; r++) {
201	      const dr = r - 2.5;
202	      for (let c = 0; c < COLS; c++) {
203	        const dc = c - 6.5;
204	        let base, spread;
205	        switch (pidx) {
206	          case 0: base = Math.atan2(dr * 2.2, dc) * (180 / Math.PI) + 90 + t * 14; spread = 44; break;
207	          case 1: base = t * 26 + dc * 9 + dr * 4; spread = 0; break;
208	          case 2: base = Math.atan2(dr, dc) * (180 / Math.PI) + t * 20; spread = 72 + Math.sin(t * 0.65) * 24; break;
209	          default: {
210	            const dist = Math.sqrt(dr * dr + dc * dc * 0.3) + 0.1;
211	            base = Math.atan2(dr, dc) * (180 / Math.PI) + t * 28 + dist * 18;
212	            spread = 55 + Math.sin(t * 0.4 + dist) * 20;
213	          }
214	        }
215	        buf[i][0] = spread ? base - spread / 2 : base;
216	        buf[i][1] = spread ? base + spread / 2 : base + 180;
217	        i++;
218	      }
219	    }
220	    return buf;
221	  }
222	
223	  // ── Blended pattern angles — crossfades between adjacent patterns ─────────
224	  // Each pattern occupies TRANS_START/4 ms. During the last BLEND_MS of each
225	  // pattern slot the hands smoothly interpolate into the next pattern.
226	  const PATTERN_DUR = TRANS_START / 4;   // 5 750 ms per pattern
227	  const BLEND_MS    = 1200;              // crossfade window
228	
229	  function blendedPatternAngles(t, pos) {
230	    const rawIdx    = pos / PATTERN_DUR;
231	    const pidx      = Math.min(Math.floor(rawIdx), 3);
232	    const phase     = rawIdx - pidx;           // 0..1 within this slot
233	    const blendFrac = 1 - BLEND_MS / PATTERN_DUR;
234	
235	    if (pidx >= 3 || phase < blendFrac) {
236	      return patternAngles(t, pidx, _bufOut);
237	    }
238	
