  'use strict';

  // ── Default config (override via /clock-controls.html + localStorage) ──────
  const DEFAULTS = {
    mode:          'clock',     // 'clock' | 'countdown'
    useLocal:      true,        // true = local time via Date(); false = UTC + offset
